import React, { useContext } from "react";
import { useNavigate } from "react-router-dom";
import { Button, Typography, Box } from "@mui/material";
import { AuthContext } from "../contexts/AuthContext"; // 假設您有一個 AuthContext

function Home() {
  const { isAuthenticated } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleEnterLobby = () => {
    if (isAuthenticated) {
      navigate("/lobby");
    } else {
      // 如果用戶未登入，可以顯示一個提示或者直接導向登入頁面
      navigate("/login");
    }
  };

  return (
    <Box sx={{ textAlign: "center", mt: 4 }}>
      <Typography variant="h4" gutterBottom>
        歡迎來到聊天室
      </Typography>
      <Box sx={{ "& > *": { m: 1 } }}>
        <Button onClick={handleEnterLobby} variant="contained">
          {isAuthenticated ? "進入大廳" : "登入以進入大廳"}
        </Button>
        {!isAuthenticated && (
          <>
            <Button onClick={() => navigate("/login")} variant="outlined">
              登入
            </Button>
            <Button onClick={() => navigate("/register")} variant="outlined">
              註冊
            </Button>
          </>
        )}
      </Box>
    </Box>
  );
}

export default Home;
